arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

var rawData = mlContext.Data.LoadFromTextFile<CustomerInput>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" → boolean label
var mappedData = mlContext.Transforms.CustomMapping<CustomerInput, MappedCustomer>(
    (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
    contractName: "ChurnMapping")
    .Fit(rawData).Transform(rawData);

var split = mlContext.Data.TrainTestSplit(mappedData, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerInput.Age),
        nameof(CustomerInput.Income),
        nameof(CustomerInput.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);

Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                  $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, mappedData.Schema, modelPath);

// --- Register pooled prediction engine ---
builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => new
{
    auc = metrics.AreaUnderRocCurve,
    accuracy = metrics.Accuracy,
    f1 = metrics.F1Score
});

app.MapPost("/predict", (ChurnInput input, PredictionEnginePool<ChurnInput, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(input);
    return new
    {
        willChurn = prediction.PredictedLabel,
        probability = prediction.Probability,
        score = prediction.Score
    };
});

app.Run();

// --- Data models ---

public class CustomerInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

public class MappedCustomer
{
    public bool Label { get; set; }
}

// Prediction input — no label column
public class ChurnInput
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = "";
    public float PurchaseHistory { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

